| MCP:zelp41 |         genres: tagContents(node, 'Genres'),
| MCP:zelp41 |         directors: _parseDirectors(node.findAllElements('Director')),
| MCP:zelp41 |         actors: _parseActors(node.findAllElements('Actor')),
| MCP:zelp41 |         lengthInMinutes: tagContents(node, 'LengthInMinutes'),
| MCP:zelp41 |         shortSynopsis: tagContents(node, 'ShortSynopsis'),
| MCP:zelp41 |         synopsis: tagContents(node, 'Synopsis'),
