| MCP:zelp41 | class EventImageDataParser {
| MCP:zelp41 |   static EventImageData parse(Iterable<xml.XmlElement> roots) {
| MCP:zelp41 |     if (roots == null || roots.isEmpty) {
| MCP:zelp41 |       return EventImageData.empty();
| MCP:zelp41 |     }
| MCP:zelp41 | 
| MCP:zelp41 |     final root = roots.first;
| MCP:zelp41 |     final landscapeBig =
| MCP:zelp41 |         rewriteImageUrl(tagContentsOrNull(root, 'EventLargeImageLandscape'));
| MCP:zelp41 | 
| MCP:zelp41 |     return EventImageData(
| MCP:zelp41 |       portraitSmall:
| MCP:zelp41 |           rewriteImageUrl(tagContentsOrNull(root, 'EventSmallImagePortrait')),
| MCP:zelp41 |       portraitMedium:
| MCP:zelp41 |           rewriteImageUrl(tagContentsOrNull(root, 'EventMediumImagePortrait')),
| MCP:zelp41 |       portraitLarge:
| MCP:zelp41 |           rewriteImageUrl(tagContentsOrNull(root, 'EventLargeImagePortrait')),
| MCP:zelp41 |       landscapeSmall:
| MCP:zelp41 |           rewriteImageUrl(tagContentsOrNull(root, 'EventSmallImageLandscape')),
| MCP:zelp41 |       landscapeBig: landscapeBig,
| MCP:zelp41 |       landscapeHd: _getHdImageUrl(landscapeBig),
| MCP:zelp41 |       landscapeHd2: _getHdImageUrl2(landscapeBig),
| MCP:zelp41 |     );
| MCP:zelp41 |   }
| MCP:zelp41 | 
| MCP:zelp41 |   ///
| MCP:zelp41 |   /// This hacky hack only exists because Finnkino API doesn't return HD
| MCP:zelp41 |   /// landscape images without also increasing the response size by 47,4% on
| MCP:zelp41 |   /// average. Yes, it really does that by including bunch of other unnecessary
| MCP:zelp41 |   /// images.
| MCP:zelp41 |   ///
| MCP:zelp41 |   /// In order to circumvent this, we "calculate" the HD landscape image url from
| MCP:zelp41 |   /// the large landscape url.
| MCP:zelp41 |   ///
| MCP:zelp41 |   /// For example, the url:
| MCP:zelp41 |   ///
| MCP:zelp41 |   /// https://media.finnkino.fi/1012/Event_11881/landscape_large/BookClub_670_kke.jpg
| MCP:zelp41 |   ///
| MCP:zelp41 |   /// converted to landscape HD url becomes:
| MCP:zelp41 |   ///
| MCP:zelp41 |   /// https://media.finnkino.fi//1012/Event_11881/landscape_hd/BookClub_1920_kke.jpg
| MCP:zelp41 |   ///
| MCP:zelp41 |   /// OR
| MCP:zelp41 |   ///
| MCP:zelp41 |   /// https://media.finnkino.fi//1012/Event_11881/landscape_hd/BookClub_1920_kke_.jpg
| MCP:zelp41 |   ///
| MCP:zelp41 |   /// Yep. That's right. It could be either one of those. So we just try loading the other
| MCP:zelp41 |   /// and if it fails, we try loading the second one.
| MCP:zelp41 |   ///
| MCP:zelp41 |   /// The one with the "_" is more common, but the other one appears too.
| MCP:zelp41 |   ///
| MCP:zelp41 |   /// TODO: This is ugly and I should feel ugly. Make this more efficient and
| MCP:zelp41 |   /// pretty. And DRY.
| MCP:zelp41 |   /// FIXME. please.
| MCP:zelp41 |   ///
| MCP:zelp41 |   static final _regex = RegExp(r'_670([^.]*)');
| MCP:zelp41 | 
| MCP:zelp41 |   static String _getHdImageUrl(String bigUrl) {
| MCP:zelp41 |     return bigUrl
| MCP:zelp41 |         ?.replaceFirst('landscape_large', 'landscape_hd')
| MCP:zelp41 |         ?.replaceFirstMapped(_regex, (match) => '_1920${match.group(1)}_');
| MCP:zelp41 |   }
| MCP:zelp41 | 
| MCP:zelp41 |   static String _getHdImageUrl2(String bigUrl) {
| MCP:zelp41 |     return bigUrl
| MCP:zelp41 |         ?.replaceFirst('landscape_large', 'landscape_hd')
| MCP:zelp41 |         ?.replaceFirstMapped(_regex, (match) => '_1920${match.group(1)}');
| MCP:zelp41 |   }
| MCP:zelp41 | }

