| MCP:zelp41 | String tagContents(xml.XmlElement node, String tagName) {
| MCP:zelp41 |   final contents = tagContentsOrNull(node, tagName);
| MCP:zelp41 | 
| MCP:zelp41 |   if (contents == null) {
| MCP:zelp41 |     throw ArgumentError('Contents for $tagName were unexpectedly null.');
| MCP:zelp41 |   }
| MCP:zelp41 | 
| MCP:zelp41 |   return contents;
| MCP:zelp41 | }
| MCP:zelp41 | 
| MCP:zelp41 | String tagContentsOrNull(xml.XmlElement node, String tagName) {
| MCP:zelp41 |   final matches = node.findElements(tagName);
| MCP:zelp41 | 
| MCP:zelp41 |   if (matches.isNotEmpty) {
| MCP:zelp41 |     return matches.single.text;
| MCP:zelp41 |   }
| MCP:zelp41 | 
| MCP:zelp41 |   return null;
| MCP:zelp41 | }

