| MCP:zelp41 | class ShowMiddleware extends MiddlewareClass<AppState> {
| MCP:zelp41 |   ShowMiddleware(this.api);
| MCP:zelp41 | 
| MCP:zelp41 |   final FinnkinoApi api;
| MCP:zelp41 | 
| MCP:zelp41 |   @override
| MCP:zelp41 |   Future<Null> call(
| MCP:zelp41 |       Store<AppState> store, dynamic action, NextDispatcher next) async {
| MCP:zelp41 |     next(action);
| MCP:zelp41 | 
| MCP:zelp41 |     if (action is InitCompleteAction || action is UpdateShowDatesAction) {
| MCP:zelp41 |       await _updateShowDates(action, next);
| MCP:zelp41 |     }
| MCP:zelp41 | 
| MCP:zelp41 |     if (action is ChangeCurrentTheaterAction ||
| MCP:zelp41 |         action is RefreshShowsAction ||
| MCP:zelp41 |         action is ChangeCurrentDateAction) {
| MCP:zelp41 |       await _updateCurrentShows(store, action, next);
| MCP:zelp41 |     }
| MCP:zelp41 | 
| MCP:zelp41 |     if (action is FetchShowsIfNotLoadedAction) {
| MCP:zelp41 |       if (store.state.showState.loadingStatus == LoadingStatus.idle) {
| MCP:zelp41 |         await _updateCurrentShows(store, action, next);
| MCP:zelp41 |       }
| MCP:zelp41 |     }
| MCP:zelp41 |   }
| MCP:zelp41 | 
| MCP:zelp41 |   void _updateShowDates(dynamic action, NextDispatcher next) {
| MCP:zelp41 |     final now = Clock.getCurrentTime();
| MCP:zelp41 |     var dates =
| MCP:zelp41 |         listFrom(List.generate(7, (index) => now.add(Duration(days: index))));
| MCP:zelp41 | 
| MCP:zelp41 |     next(new ShowDatesUpdatedAction(dates));
| MCP:zelp41 |   }
| MCP:zelp41 | 
| MCP:zelp41 |   Future<void> _updateCurrentShows(
| MCP:zelp41 |       Store<AppState> store, dynamic action, NextDispatcher next) async {
| MCP:zelp41 |     next(RequestingShowsAction());
| MCP:zelp41 | 
| MCP:zelp41 |     try {
| MCP:zelp41 |       final theater = _getCorrectTheater(store, action);
| MCP:zelp41 |       final date = _getCorrectDate(store, action);
| MCP:zelp41 |       final cacheKey = DateTheaterPair(date, theater);
| MCP:zelp41 | 
| MCP:zelp41 |       var shows = store.state.showState.shows[cacheKey];
| MCP:zelp41 | 
| MCP:zelp41 |       if (shows == null) {
| MCP:zelp41 |         shows = await _fetchShows(date, theater, next);
| MCP:zelp41 |       }
| MCP:zelp41 | 
| MCP:zelp41 |       next(ReceivedShowsAction(DateTheaterPair(date, theater), shows));
| MCP:zelp41 |     } catch (e) {
| MCP:zelp41 |       next(ErrorLoadingShowsAction());
| MCP:zelp41 |     }
| MCP:zelp41 |   }
| MCP:zelp41 | 
| MCP:zelp41 |   Future<KtList<Show>> _fetchShows(
| MCP:zelp41 |       DateTime currentDate, Theater newTheater, NextDispatcher next) async {
| MCP:zelp41 |     final shows = await api.getSchedule(newTheater, currentDate);
| MCP:zelp41 |     final now = Clock.getCurrentTime();
| MCP:zelp41 | 
| MCP:zelp41 |     // Return only show times that haven't started yet.
| MCP:zelp41 |     return shows.filter((show) => show.start.isAfter(now));
| MCP:zelp41 |   }
| MCP:zelp41 | 
| MCP:zelp41 |   Theater _getCorrectTheater(Store<AppState> store, dynamic action) {
| MCP:zelp41 |     return action is InitCompleteAction || action is ChangeCurrentTheaterAction
| MCP:zelp41 |         ? action.selectedTheater
| MCP:zelp41 |         : store.state.theaterState.currentTheater;
| MCP:zelp41 |   }
| MCP:zelp41 | 
| MCP:zelp41 |   DateTime _getCorrectDate(Store<AppState> store, dynamic action) {
| MCP:zelp41 |     return action is ChangeCurrentDateAction
| MCP:zelp41 |         ? action.date
| MCP:zelp41 |         : store.state.showState.selectedDate;
| MCP:zelp41 |   }
| MCP:zelp41 | }

